import json

lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))

# Look for any additional exception info, reason strings
for key in sorted(crash.keys()):
    if key not in ['threads', 'usedImages', 'vmSummary']:
        val = crash[key]
        if isinstance(val, (str, int, float, bool)):
            print(f"{key}: {val}")
        elif isinstance(val, dict) and len(json.dumps(val)) < 500:
            print(f"{key}: {json.dumps(val)}")
        elif isinstance(val, list) and len(json.dumps(val)) < 500:
            print(f"{key}: {json.dumps(val)}")
        else:
            print(f"{key}: <{type(val).__name__}, len={len(val) if hasattr(val,'__len__') else '?'}>")
